-- =============================================================================
SELECT * FROM(SELECT DISTINCT PGM_YR,ADM_ST_FSA_CD,ADM_CNTY_FSA_CD,SGNP_TYPE_DESC,SGNP_STYPE_DESC,SGNP_NBR,SGNP_STYPE_AGR_NM,TR_NBR,OFR_SCNR_NM,FLD_NBR,CNSV_PRAC_CD,NTL_EBI_NM,FARM_NBR,CALC_EBI_FCTR_PNT_NBR,EBI_FCTR_PNT_NBR,SGNP_FCTR_MOD_DESC,OFR_SCNR_ID,PRAC_SEQ_NBR,SGNP_ID,NTL_EBI_FCTR_ID,NTL_EBI_SFCTR_ID,DATA_STAT_CD,CRE_DT,LAST_CHG_DT,LAST_CHG_USER_NM,-- op,ROW_NUMBER() over ( partition by OFR_SCNR_ID,PRAC_SEQ_NBR,SGNP_ID,NTL_EBI_FCTR_ID,NTL_EBI_SFCTR_IDorder by TBL_PRIORITY ASC, LAST_CHG_DT DESC ) AS row_num_partFROM(SELECT ewt40ofrsc.PGM_YR PGM_YR,ewt40ofrsc.ADM_ST_FSA_CD ADM_ST_FSA_CD,ewt40ofrsc.ADM_CNTY_FSA_CD ADM_CNTY_FSA_CD,ewt14sgnp.SGNP_TYPE_DESC SGNP_TYPE_DESC,ewt14sgnp.SGNP_STYPE_DESC SGNP_STYPE_DESC,ewt14sgnp.SGNP_NBR SGNP_NBR,ewt14sgnp.SGNP_STYPE_AGR_NM SGNP_STYPE_AGR_NM,ewt40ofrsc.TR_NBR TR_NBR,ewt40ofrsc.OFR_SCNR_NM OFR_SCNR_NM,ewt42ofprac.FLD_NBR FLD_NBR,ewt42ofprac.CNSV_PRAC_CD CNSV_PRAC_CD,ewt94nebi.NTL_EBI_NM NTL_EBI_NM,ewt40ofrsc.FARM_NBR FARM_NBR,ewt50prce.CALC_EBI_FCTR_NBR CALC_EBI_FCTR_PNT_NBR,ewt50prce.EBI_FCTR_PNT_NBR EBI_FCTR_PNT_NBR,ewt50prce.SGNP_FCTR_MOD_DESC SGNP_FCTR_MOD_DESC,ewt50prce.OFR_SCNR_ID OFR_SCNR_ID,ewt50prce.PRAC_SEQ_NBR PRAC_SEQ_NBR,ewt50prce.SGNP_ID SGNP_ID,ewt50prce.NTL_EBI_FCTR_ID NTL_EBI_FCTR_ID,ewt50prce.NTL_EBI_SFCTR_ID NTL_EBI_SFCTR_ID,ewt50prce.DATA_STAT_CD DATA_STAT_CD,ewt50prce.CRE_DT CRE_DT,ewt50prce.LAST_CHG_DT LAST_CHG_DT,ewt50prce.LAST_CHG_USER_NM LAST_CHG_USER_NM,-- op,1 AS TBL_PRIORITYFROM "fsa-prod-cnsv".EWT50PRCE LEFT JOIN "fsa-prod-cnsv".EWT42OFPRAC ON (EWT50PRCE.OFR_SCNR_ID = EWT42OFPRAC.OFR_SCNR_ID AND EWT50PRCE.PRAC_SEQ_NBR = EWT42OFPRAC.PRAC_SEQ_NBR) LEFT JOIN "fsa-prod-cnsv".EWT40OFRSC ON (EWT42OFPRAC.OFR_SCNR_ID = EWT40OFRSC.OFR_SCNR_ID) LEFT JOIN "fsa-prod-cnsv".EWT85SEBI ON (EWT50PRCE.SGNP_ID = EWT85SEBI.SGNP_ID AND EWT50PRCE.NTL_EBI_FCTR_ID = EWT85SEBI.NTL_EBI_FCTR_ID AND EWT50PRCE.NTL_EBI_SFCTR_ID = EWT85SEBI.NTL_EBI_SFCTR_ID) LEFT JOIN "fsa-prod-cnsv".EWT94NEBI ON (EWT85SEBI.NTL_EBI_FCTR_ID = EWT94NEBI.NTL_EBI_FCTR_ID AND EWT85SEBI.NTL_EBI_SFCTR_ID = EWT94NEBI.NTL_EBI_SFCTR_ID) LEFT JOIN "fsa-prod-cnsv".EWT14SGNP ON (EWT85SEBI.SGNP_ID = EWT14SGNP.SGNP_ID AND EWT40OFRSC.SGNP_ID = EWT14SGNP.SGNP_ID)--WHERE __CDC_OPERATION <> 'D'

UNIONSELECT ewt40ofrsc.PGM_YR PGM_YR,ewt40ofrsc.ADM_ST_FSA_CD ADM_ST_FSA_CD,ewt40ofrsc.ADM_CNTY_FSA_CD ADM_CNTY_FSA_CD,ewt14sgnp.SGNP_TYPE_DESC SGNP_TYPE_DESC,ewt14sgnp.SGNP_STYPE_DESC SGNP_STYPE_DESC,ewt14sgnp.SGNP_NBR SGNP_NBR,ewt14sgnp.SGNP_STYPE_AGR_NM SGNP_STYPE_AGR_NM,ewt40ofrsc.TR_NBR TR_NBR,ewt40ofrsc.OFR_SCNR_NM OFR_SCNR_NM,ewt42ofprac.FLD_NBR FLD_NBR,ewt42ofprac.CNSV_PRAC_CD CNSV_PRAC_CD,ewt94nebi.NTL_EBI_NM NTL_EBI_NM,ewt40ofrsc.FARM_NBR FARM_NBR,ewt50prce.CALC_EBI_FCTR_NBR CALC_EBI_FCTR_PNT_NBR,ewt50prce.EBI_FCTR_PNT_NBR EBI_FCTR_PNT_NBR,ewt50prce.SGNP_FCTR_MOD_DESC SGNP_FCTR_MOD_DESC,ewt50prce.OFR_SCNR_ID OFR_SCNR_ID,ewt50prce.PRAC_SEQ_NBR PRAC_SEQ_NBR,ewt50prce.SGNP_ID SGNP_ID,ewt50prce.NTL_EBI_FCTR_ID NTL_EBI_FCTR_ID,ewt50prce.NTL_EBI_SFCTR_ID NTL_EBI_SFCTR_ID,ewt50prce.DATA_STAT_CD DATA_STAT_CD,ewt50prce.CRE_DT CRE_DT,ewt50prce.LAST_CHG_DT LAST_CHG_DT,ewt50prce.LAST_CHG_USER_NM LAST_CHG_USER_NM,-- op,2 AS TBL_PRIORITYFROM "fsa-prod-cnsv".EWT42OFPRAC JOIN "fsa-prod-cnsv".EWT50PRCE ON (EWT42OFPRAC.OFR_SCNR_ID = EWT50PRCE.OFR_SCNR_ID AND EWT42OFPRAC.PRAC_SEQ_NBR = EWT50PRCE.PRAC_SEQ_NBR) LEFT JOIN "fsa-prod-cnsv".EWT40OFRSC ON (EWT42OFPRAC.OFR_SCNR_ID = EWT40OFRSC.OFR_SCNR_ID) LEFT JOIN "fsa-prod-cnsv".EWT85SEBI ON (EWT50PRCE.SGNP_ID = EWT85SEBI.SGNP_ID AND EWT50PRCE.NTL_EBI_FCTR_ID = EWT85SEBI.NTL_EBI_FCTR_ID AND EWT50PRCE.NTL_EBI_SFCTR_ID = EWT85SEBI.NTL_EBI_SFCTR_ID) LEFT JOIN "fsa-prod-cnsv".EWT94NEBI ON (EWT85SEBI.NTL_EBI_FCTR_ID = EWT94NEBI.NTL_EBI_FCTR_ID AND EWT85SEBI.NTL_EBI_SFCTR_ID = EWT94NEBI.NTL_EBI_SFCTR_ID) LEFT JOIN "fsa-prod-cnsv".EWT14SGNP ON (EWT85SEBI.SGNP_ID = EWT14SGNP.SGNP_ID AND EWT40OFRSC.SGNP_ID = EWT14SGNP.SGNP_ID)-- WHERE __CDC_OPERATION <> 'D'

UNIONSELECT ewt40ofrsc.PGM_YR PGM_YR,ewt40ofrsc.ADM_ST_FSA_CD ADM_ST_FSA_CD,ewt40ofrsc.ADM_CNTY_FSA_CD ADM_CNTY_FSA_CD,ewt14sgnp.SGNP_TYPE_DESC SGNP_TYPE_DESC,ewt14sgnp.SGNP_STYPE_DESC SGNP_STYPE_DESC,ewt14sgnp.SGNP_NBR SGNP_NBR,ewt14sgnp.SGNP_STYPE_AGR_NM SGNP_STYPE_AGR_NM,ewt40ofrsc.TR_NBR TR_NBR,ewt40ofrsc.OFR_SCNR_NM OFR_SCNR_NM,ewt42ofprac.FLD_NBR FLD_NBR,ewt42ofprac.CNSV_PRAC_CD CNSV_PRAC_CD,ewt94nebi.NTL_EBI_NM NTL_EBI_NM,ewt40ofrsc.FARM_NBR FARM_NBR,ewt50prce.CALC_EBI_FCTR_NBR CALC_EBI_FCTR_PNT_NBR,ewt50prce.EBI_FCTR_PNT_NBR EBI_FCTR_PNT_NBR,ewt50prce.SGNP_FCTR_MOD_DESC SGNP_FCTR_MOD_DESC,ewt50prce.OFR_SCNR_ID OFR_SCNR_ID,ewt50prce.PRAC_SEQ_NBR PRAC_SEQ_NBR,ewt50prce.SGNP_ID SGNP_ID,ewt50prce.NTL_EBI_FCTR_ID NTL_EBI_FCTR_ID,ewt50prce.NTL_EBI_SFCTR_ID NTL_EBI_SFCTR_ID,ewt50prce.DATA_STAT_CD DATA_STAT_CD,ewt50prce.CRE_DT CRE_DT,ewt50prce.LAST_CHG_DT LAST_CHG_DT,ewt50prce.LAST_CHG_USER_NM LAST_CHG_USER_NM,-- op,3 AS TBL_PRIORITYFROM "fsa-prod-cnsv".EWT40OFRSC LEFT JOIN "fsa-prod-cnsv".EWT42OFPRAC ON (EWT40OFRSC.OFR_SCNR_ID = EWT42OFPRAC.OFR_SCNR_ID) JOIN "fsa-prod-cnsv".EWT50PRCE ON (EWT42OFPRAC.OFR_SCNR_ID = EWT50PRCE.OFR_SCNR_ID AND EWT42OFPRAC.PRAC_SEQ_NBR = EWT50PRCE.PRAC_SEQ_NBR) LEFT JOIN "fsa-prod-cnsv".EWT85SEBI ON (EWT50PRCE.SGNP_ID = EWT85SEBI.SGNP_ID AND EWT50PRCE.NTL_EBI_FCTR_ID = EWT85SEBI.NTL_EBI_FCTR_ID AND EWT50PRCE.NTL_EBI_SFCTR_ID = EWT85SEBI.NTL_EBI_SFCTR_ID) LEFT JOIN "fsa-prod-cnsv".EWT94NEBI ON (EWT85SEBI.NTL_EBI_FCTR_ID = EWT94NEBI.NTL_EBI_FCTR_ID AND EWT85SEBI.NTL_EBI_SFCTR_ID = EWT94NEBI.NTL_EBI_SFCTR_ID) LEFT JOIN "fsa-prod-cnsv".EWT14SGNP ON (EWT85SEBI.SGNP_ID = EWT14SGNP.SGNP_ID AND EWT40OFRSC.SGNP_ID = EWT14SGNP.SGNP_ID)-- WHERE __CDC_OPERATION <> 'D'UNIONSELECT ewt40ofrsc.PGM_YR PGM_YR,ewt40ofrsc.ADM_ST_FSA_CD ADM_ST_FSA_CD,ewt40ofrsc.ADM_CNTY_FSA_CD ADM_CNTY_FSA_CD,ewt14sgnp.SGNP_TYPE_DESC SGNP_TYPE_DESC,ewt14sgnp.SGNP_STYPE_DESC SGNP_STYPE_DESC,ewt14sgnp.SGNP_NBR SGNP_NBR,ewt14sgnp.SGNP_STYPE_AGR_NM SGNP_STYPE_AGR_NM,ewt40ofrsc.TR_NBR TR_NBR,ewt40ofrsc.OFR_SCNR_NM OFR_SCNR_NM,ewt42ofprac.FLD_NBR FLD_NBR,ewt42ofprac.CNSV_PRAC_CD CNSV_PRAC_CD,ewt94nebi.NTL_EBI_NM NTL_EBI_NM,ewt40ofrsc.FARM_NBR FARM_NBR,ewt50prce.CALC_EBI_FCTR_NBR CALC_EBI_FCTR_PNT_NBR,ewt50prce.EBI_FCTR_PNT_NBR EBI_FCTR_PNT_NBR,ewt50prce.SGNP_FCTR_MOD_DESC SGNP_FCTR_MOD_DESC,ewt50prce.OFR_SCNR_ID OFR_SCNR_ID,ewt50prce.PRAC_SEQ_NBR PRAC_SEQ_NBR,ewt50prce.SGNP_ID SGNP_ID,ewt50prce.NTL_EBI_FCTR_ID NTL_EBI_FCTR_ID,ewt50prce.NTL_EBI_SFCTR_ID NTL_EBI_SFCTR_ID,ewt50prce.DATA_STAT_CD DATA_STAT_CD,ewt50prce.CRE_DT CRE_DT,ewt50prce.LAST_CHG_DT LAST_CHG_DT,ewt50prce.LAST_CHG_USER_NM LAST_CHG_USER_NM,-- op,4 AS TBL_PRIORITYFROM "fsa-prod-cnsv".EWT85SEBI JOIN "fsa-prod-cnsv".EWT50PRCE ON (EWT85SEBI.SGNP_ID = EWT50PRCE.SGNP_ID AND EWT85SEBI.NTL_EBI_FCTR_ID = EWT50PRCE.NTL_EBI_FCTR_ID AND EWT85SEBI.NTL_EBI_SFCTR_ID = EWT50PRCE.NTL_EBI_SFCTR_ID) LEFT JOIN "fsa-prod-cnsv".EWT42OFPRAC ON (EWT50PRCE.OFR_SCNR_ID = EWT42OFPRAC.OFR_SCNR_ID AND EWT50PRCE.PRAC_SEQ_NBR = EWT42OFPRAC.PRAC_SEQ_NBR) LEFT JOIN "fsa-prod-cnsv".EWT40OFRSC ON (EWT42OFPRAC.OFR_SCNR_ID = EWT40OFRSC.OFR_SCNR_ID) LEFT JOIN "fsa-prod-cnsv".EWT94NEBI ON (EWT85SEBI.NTL_EBI_FCTR_ID = EWT94NEBI.NTL_EBI_FCTR_ID AND EWT85SEBI.NTL_EBI_SFCTR_ID = EWT94NEBI.NTL_EBI_SFCTR_ID) LEFT JOIN "fsa-prod-cnsv".EWT14SGNP ON (EWT85SEBI.SGNP_ID = EWT14SGNP.SGNP_ID AND EWT40OFRSC.SGNP_ID = EWT14SGNP.SGNP_ID)-- WHERE __CDC_OPERATION <> 'D'

UNIONSELECT ewt40ofrsc.PGM_YR PGM_YR,ewt40ofrsc.ADM_ST_FSA_CD ADM_ST_FSA_CD,ewt40ofrsc.ADM_CNTY_FSA_CD ADM_CNTY_FSA_CD,ewt14sgnp.SGNP_TYPE_DESC SGNP_TYPE_DESC,ewt14sgnp.SGNP_STYPE_DESC SGNP_STYPE_DESC,ewt14sgnp.SGNP_NBR SGNP_NBR,ewt14sgnp.SGNP_STYPE_AGR_NM SGNP_STYPE_AGR_NM,ewt40ofrsc.TR_NBR TR_NBR,ewt40ofrsc.OFR_SCNR_NM OFR_SCNR_NM,ewt42ofprac.FLD_NBR FLD_NBR,ewt42ofprac.CNSV_PRAC_CD CNSV_PRAC_CD,ewt94nebi.NTL_EBI_NM NTL_EBI_NM,ewt40ofrsc.FARM_NBR FARM_NBR,ewt50prce.CALC_EBI_FCTR_NBR CALC_EBI_FCTR_PNT_NBR,ewt50prce.EBI_FCTR_PNT_NBR EBI_FCTR_PNT_NBR,ewt50prce.SGNP_FCTR_MOD_DESC SGNP_FCTR_MOD_DESC,ewt50prce.OFR_SCNR_ID OFR_SCNR_ID,ewt50prce.PRAC_SEQ_NBR PRAC_SEQ_NBR,ewt50prce.SGNP_ID SGNP_ID,ewt50prce.NTL_EBI_FCTR_ID NTL_EBI_FCTR_ID,ewt50prce.NTL_EBI_SFCTR_ID NTL_EBI_SFCTR_ID,ewt50prce.DATA_STAT_CD DATA_STAT_CD,ewt50prce.CRE_DT CRE_DT,ewt50prce.LAST_CHG_DT LAST_CHG_DT,ewt50prce.LAST_CHG_USER_NM LAST_CHG_USER_NM,-- op,5 AS TBL_PRIORITYFROM "fsa-prod-cnsv".EWT94NEBI LEFT JOIN "fsa-prod-cnsv".EWT85SEBI ON (EWT94NEBI.NTL_EBI_FCTR_ID = EWT85SEBI.NTL_EBI_FCTR_ID AND EWT94NEBI.NTL_EBI_SFCTR_ID = EWT85SEBI.NTL_EBI_SFCTR_ID) JOIN "fsa-prod-cnsv".EWT50PRCE ON (EWT85SEBI.SGNP_ID = EWT50PRCE.SGNP_ID AND EWT85SEBI.NTL_EBI_FCTR_ID = EWT50PRCE.NTL_EBI_FCTR_ID AND EWT85SEBI.NTL_EBI_SFCTR_ID = EWT50PRCE.NTL_EBI_SFCTR_ID) LEFT JOIN "fsa-prod-cnsv".EWT42OFPRAC ON (EWT50PRCE.OFR_SCNR_ID = EWT42OFPRAC.OFR_SCNR_ID AND EWT50PRCE.PRAC_SEQ_NBR = EWT42OFPRAC.PRAC_SEQ_NBR) LEFT JOIN "fsa-prod-cnsv".EWT40OFRSC ON (EWT42OFPRAC.OFR_SCNR_ID = EWT40OFRSC.OFR_SCNR_ID) LEFT JOIN "fsa-prod-cnsv".EWT14SGNP ON (EWT85SEBI.SGNP_ID = EWT14SGNP.SGNP_ID AND EWT40OFRSC.SGNP_ID = EWT14SGNP.SGNP_ID)-- WHERE __CDC_OPERATION <> 'D'

UNIONSELECT ewt40ofrsc.PGM_YR PGM_YR,ewt40ofrsc.ADM_ST_FSA_CD ADM_ST_FSA_CD,ewt40ofrsc.ADM_CNTY_FSA_CD ADM_CNTY_FSA_CD,ewt14sgnp.SGNP_TYPE_DESC SGNP_TYPE_DESC,ewt14sgnp.SGNP_STYPE_DESC SGNP_STYPE_DESC,ewt14sgnp.SGNP_NBR SGNP_NBR,ewt14sgnp.SGNP_STYPE_AGR_NM SGNP_STYPE_AGR_NM,ewt40ofrsc.TR_NBR TR_NBR,ewt40ofrsc.OFR_SCNR_NM OFR_SCNR_NM,ewt42ofprac.FLD_NBR FLD_NBR,ewt42ofprac.CNSV_PRAC_CD CNSV_PRAC_CD,ewt94nebi.NTL_EBI_NM NTL_EBI_NM,ewt40ofrsc.FARM_NBR FARM_NBR,ewt50prce.CALC_EBI_FCTR_NBR CALC_EBI_FCTR_PNT_NBR,ewt50prce.EBI_FCTR_PNT_NBR EBI_FCTR_PNT_NBR,ewt50prce.SGNP_FCTR_MOD_DESC SGNP_FCTR_MOD_DESC,ewt50prce.OFR_SCNR_ID OFR_SCNR_ID,ewt50prce.PRAC_SEQ_NBR PRAC_SEQ_NBR,ewt50prce.SGNP_ID SGNP_ID,ewt50prce.NTL_EBI_FCTR_ID NTL_EBI_FCTR_ID,ewt50prce.NTL_EBI_SFCTR_ID NTL_EBI_SFCTR_ID,ewt50prce.DATA_STAT_CD DATA_STAT_CD,ewt50prce.CRE_DT CRE_DT,ewt50prce.LAST_CHG_DT LAST_CHG_DT,ewt50prce.LAST_CHG_USER_NM LAST_CHG_USER_NM,-- op,6 AS TBL_PRIORITYFROM "fsa-prod-cnsv".EWT14SGNP LEFT JOIN "fsa-prod-cnsv".EWT85SEBI ON EWT14SGNP.SGNP_ID = EWT85SEBI.SGNP_ID  LEFT JOIN "fsa-prod-cnsv".EWT40OFRSC ON EWT14SGNP.SGNP_ID = EWT40OFRSC.SGNP_ID  LEFT JOIN "fsa-prod-cnsv".EWT94NEBI ON (EWT85SEBI.NTL_EBI_FCTR_ID = EWT94NEBI.NTL_EBI_FCTR_ID AND EWT85SEBI.NTL_EBI_SFCTR_ID = EWT94NEBI.NTL_EBI_SFCTR_ID) LEFT JOIN "fsa-prod-cnsv".EWT42OFPRAC ON EWT40OFRSC.OFR_SCNR_ID = EWT42OFPRAC.OFR_SCNR_ID JOIN "fsa-prod-cnsv".EWT50PRCE ON (EWT85SEBI.SGNP_ID = EWT50PRCE.SGNP_ID AND EWT85SEBI.NTL_EBI_FCTR_ID = EWT50PRCE.NTL_EBI_FCTR_ID AND EWT85SEBI.NTL_EBI_SFCTR_ID = EWT50PRCE.NTL_EBI_SFCTR_ID  AND EWT42OFPRAC.OFR_SCNR_ID = EWT50PRCE.OFR_SCNR_ID   AND EWT42OFPRAC.PRAC_SEQ_NBR = EWT50PRCE.PRAC_SEQ_NBR) -- WHERE __CDC_OPERATION <> 'D') STG_ALL) STG_UNQWHERE row_num_part = 1AND (
 (COALESCE(CAST(CRE_DT AS DATE), DATE '1900-01-01') <= CAST('2025-07-01' AS DATE))
    AND
    (COALESCE(CAST(LAST_CHG_DT AS DATE), DATE '1900-01-01') <= CAST('2025-07-01' AS DATE))
)

UNIONSELECT DISTINCTNULL PGM_YR,NULL ADM_ST_FSA_CD,NULL ADM_CNTY_FSA_CD,NULL SGNP_TYPE_DESC,NULL SGNP_STYPE_DESC,NULL SGNP_NBR,NULL SGNP_STYPE_AGR_NM,NULL TR_NBR,NULL OFR_SCNR_NM,NULL FLD_NBR,NULL CNSV_PRAC_CD,NULL NTL_EBI_NM,NULL FARM_NBR,ewt50prce.CALC_EBI_FCTR_NBR CALC_EBI_FCTR_PNT_NBR,ewt50prce.EBI_FCTR_PNT_NBR EBI_FCTR_PNT_NBR,ewt50prce.SGNP_FCTR_MOD_DESC SGNP_FCTR_MOD_DESC,ewt50prce.OFR_SCNR_ID OFR_SCNR_ID,ewt50prce.PRAC_SEQ_NBR PRAC_SEQ_NBR,ewt50prce.SGNP_ID SGNP_ID,ewt50prce.NTL_EBI_FCTR_ID NTL_EBI_FCTR_ID,ewt50prce.NTL_EBI_SFCTR_ID NTL_EBI_SFCTR_ID,ewt50prce.DATA_STAT_CD DATA_STAT_CD,ewt50prce.CRE_DT CRE_DT,ewt50prce.LAST_CHG_DT LAST_CHG_DT,ewt50prce.LAST_CHG_USER_NM LAST_CHG_USER_NM,-- op,1 AS row_num_partFROM "fsa-prod-cnsv".ewt50prce--WHERE __CDC_OPERATION = 'D'